parameters.jsCode:
const body = $input.item.json.body;
const event = $input.item.headers?.['x-github-event'] || '';
const action = body?.action || '';
const conclusion = body?.workflow_run?.conclusion || '';
const repo = body?.repository?.full_name || '';
const workflow = body?.workflow_run?.name || '';
const branch = body?.workflow_run?.head_branch || '';
const sha = (body?.workflow_run?.head_sha || '').substring(0, 7);
const commitMsg = body?.workflow_run?.head_commit?.message || '';
const runUrl = body?.workflow_run?.html_url || '';

const isFailure = event === 'workflow_run' && action === 'completed' && conclusion === 'failure';
const isNexusCore = repo.includes('nexus-core');

return [{ json: { isFailure, isNexusCore, repo, workflow, branch, sha, commitMsg: commitMsg.split('\n')[0], runUrl } }];

